#include <stdio.h>
#include <stdlib.h>

struct Node {
    int data;
    struct Node *left, *right;
};

struct Node* search(struct Node* root, int key) {
    // Base case: root is NULL or key is at root
    if (root == NULL || root->data == key)
        return root;

    // Key is greater than root's data
    if (key > root->data)
        return search(root->right, key);

    // Key is smaller than root's data
    return search(root->left, key);
}

// Iterative version
struct Node* searchIterative(struct Node* root, int key) {
    while (root != NULL && root->data != key) {
        if (key < root->data)
            root = root->left;
        else
            root = root->right;
    }
    return root;
}

public class TreeFromTraversals {

    static int preIndex = 0;

    // Build tree from preorder and inorder
    static Node buildTree(int[] preorder, int[] inorder, 
                          int inStart, int inEnd) {
        if (inStart > inEnd)
            return null;

        // Pick current node from preorder
        Node curr = new Node(preorder[preIndex++]);

        // If only one node
        if (inStart == inEnd)
            return curr;

        // Find index in inorder
        int inIndex = search(inorder, inStart, inEnd, curr.data);

        // Build left and right subtrees
        curr.left = buildTree(preorder, inorder, inStart, inIndex - 1);
        curr.right = buildTree(preorder, inorder, inIndex + 1, inEnd);

        return curr;
    }

    static int search(int[] arr, int start, int end, int value) {
        for (int i = start; i <= end; i++) {
            if (arr[i] == value)
                return i;
        }
        return -1;
    }

    static class Node {
        int data;
        Node left, right;
        Node(int d) { data = d; }
    }
}
